+---
+// Astro component, SSG-rendered shell. The script tag below runs in
+// the browser only — it imports the textsift package via Vite's
+// normal module graph (declared as `file:..` in docs-site/package.json).
+//
+// Educational layout: every option you can pass to PrivacyFilter is
+// surfaced as a control. The Code section below shows the equivalent
+// JS for the current configuration so a reader can copy-paste it.
+
+// Astro's template parser treats raw `{` as JSX expression delimiters
+// even inside <textarea> bodies, so the JSON example needs to live in
+// a frontmatter constant and be injected via set:html.
+const DEFAULT_MARKERS_JSON = `{
+  "private_email": "[EMAIL]",
+  "private_phone": "[PHONE]",
+  "secret": null
+}`;
+---
+
+<div class="ts-playground">
+  <details class="ts-config" open>
+    <summary><strong>1. Configuration</strong> <span class="ts-hint">— change anything, then click Reload</span></summary>
+    <div class="ts-config-grid">
+      <label class="ts-field">
+        <span>Backend</span>
+        <select id="ts-backend">
+          <option value="auto" selected>auto (transformers.js — uses GPU when available, falls back to CPU)</option>
+          <option value="webgpu">webgpu (custom WGSL kernels — fastest in browser)</option>
+          <option value="wasm">wasm (custom Zig+SIMD — parallel worker pool if COOP/COEP headers are set, else single-thread)</option>
+        </select>
+      </label>
+
+      <label class="ts-field">
+        <span>Model source URL <span class="ts-hint">(an HTTP origin that hosts <code>onnx/model_q4f16.onnx</code> + <code>config.json</code> — usually HuggingFace Hub or a mirror)</span></span>
+        <input
+          id="ts-model-source"
+          type="url"
+          spellcheck="false"
+          value="https://huggingface.co/openai/privacy-filter"
+        />
+      </label>
+
+      <fieldset class="ts-field ts-categories">
+        <legend>Enabled categories <span class="ts-hint">(fixed by the model — these are the 8 BIOES classes <code>openai/privacy-filter</code> was trained on)</span></legend>
+        <label title="Personal names: 'John Smith', 'Margaret', 'Dr. Lee'."><input type="checkbox" data-cat="private_person" checked> private_person</label>
+        <label title="Email addresses: 'john@example.com', 'jsmith@acme.io'."><input type="checkbox" data-cat="private_email" checked> private_email</label>
+        <label title="Phone numbers in any format: '(617) 555-0199', '617.555.0123', '+44 20 7946 0958'."><input type="checkbox" data-cat="private_phone" checked> private_phone</label>
+        <label title="Street addresses: '456 Oak Avenue, Apt 3B, Boston, MA 02134'."><input type="checkbox" data-cat="private_address" checked> private_address</label>
+        <label title="Personal URLs / sensitive links: account-recovery URLs, session-ID URLs."><input type="checkbox" data-cat="private_url" checked> private_url</label>
+        <label title="Dates of birth, dates tied to a person: 'March 12, 2018', '1985-04-23'."><input type="checkbox" data-cat="private_date" checked> private_date</label>
+        <label title="Bank / customer / IBAN / card / SSN / IDs: '9876543210', '021000089', '123-45-6789'."><input type="checkbox" data-cat="account_number" checked> account_number</label>
+        <label title="Passwords, API keys, JWTs, recovery codes — anything that grants access."><input type="checkbox" data-cat="secret" checked> secret</label>
+        <span class="ts-hint">categories are fixed by the upstream model. Unchecking just drops those spans from results — adding new categories would require retraining.</span>
+      </fieldset>
+
+      <label class="ts-field">
+        <span>Markers <span class="ts-hint">(JSON: <code>label → replacement</code>. Example pre-filled — leave blank to use defaults like <code>[private_email]</code>)</span></span>
+        <textarea id="ts-markers" rows="6" spellcheck="false" set:html={DEFAULT_MARKERS_JSON} />
+        <span class="ts-hint">String → replace span with that string. <code>null</code> → keep original text untouched (useful for "detect-only" categories). Omit a label → fall back to <code>[label]</code>.</span>
+      </label>
+
+      <div class="ts-row ts-controls">
+        <button id="ts-reload" type="button">Reload model with this config</button>
+        <span class="ts-hint" id="ts-config-hint"></span>
+      </div>
+    </div>
+  </details>
+
+  <div class="ts-row">
+    <label for="ts-input"><strong>2. Input text</strong></label>
+    <textarea id="ts-input" rows="14" spellcheck="false">Hi support team,
+
+My name is John Smith and I'm writing on behalf of my mother, Margaret Smith, who lives at 456 Oak Avenue, Apt 3B, Boston, MA 02134. She's been a customer since March 12, 2018, and her account number is 9876543210.
+
+Yesterday around 2:45pm she received a phone call from someone claiming to be from your fraud team — they asked her to confirm her bank routing number (021000089) and the last four digits of her SSN (6789). She gave them the info before realising it was probably a scam. Please reach out to me directly at (617) 555-0199 or john.smith@example.com so we can sort this out. You can also reference our earlier ticket at https://support.example.com/tickets/TKT-48211.
+
+For verification, the password reset link she clicked was https://login.example.com/r?t=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.fake-jwt-payload. We've already disabled the card ending 4242 at her request.
+
+Thanks,
+John (cell: 617.555.0123, work: jsmith@acme.io)</textarea>
+  </div>
+
+  <div class="ts-row ts-controls">
+    <button id="ts-run" type="button">Detect</button>
+    <button id="ts-redact" type="button">Redact</button>
+    <span id="ts-status" class="ts-status">idle</span>
+  </div>
+
+  <div class="ts-row">
+    <label><strong>3. Result</strong></label>
+    <div id="ts-output" class="ts-output"></div>
+  </div>
+
+  <details class="ts-row ts-details">
+    <summary>Equivalent code <span class="ts-hint">— same call you'd make from your own JS/TS project (works in browsers + Node from the single <code>textsift</code> ESM entry; no separate <code>textsift/browser</code> import is needed)</span></summary>
+    <pre id="ts-code" class="ts-code"></pre>
+  </details>
+
+  <details class="ts-row ts-details">
+    <summary>Raw result <span class="ts-hint">— the full object your code receives. <code>detect()</code> returns <code>&#123; spans, summary, ... &#125;</code>; <code>redact()</code> returns the same plus <code>redactedText</code>, <code>containsPii</code>. Each span has <code>label</code>, <code>start</code>/<code>end</code> character offsets, the matched <code>text</code>, the <code>marker</code> it'd be replaced with, and a <code>confidence</code> score 0..1.</span></summary>
+    <pre id="ts-spans" class="ts-spans"></pre>
+  </details>
+
+  <details class="ts-storage" open>
+    <summary><strong>4. Storage</strong> <span class="ts-hint">— model weights cached on this device</span></summary>
+    <div id="ts-storage-body" class="ts-storage-body">
+      <div class="ts-row ts-controls">
+        <button id="ts-refresh-storage" type="button">Refresh</button>
+        <button id="ts-wipe" type="button" class="ts-danger">Wipe cached weights</button>
+        <span id="ts-storage-status" class="ts-status"></span>
+      </div>
+      <div id="ts-storage-info" class="ts-storage-info">…</div>
+    </div>
+  </details>
+</div>
+
+<style>
+  .ts-playground {
+    display: flex;
+    flex-direction: column;
+    gap: 0.85rem;
+    margin: 1rem 0;
+  }
+  .ts-row {
+    display: flex;
+    flex-direction: column;
+    gap: 0.4rem;
+  }
+  .ts-row label { font-size: 0.95rem; }
+  .ts-controls {
+    flex-direction: row;
+    align-items: center;
+    flex-wrap: wrap;
+    gap: 0.6rem;
+    line-height: 1.4;
+  }
+  .ts-controls > * {
+    line-height: 1.4;
+    margin: 0;
+  }
+  .ts-hint {
+    font-size: 0.85rem;
+    color: var(--sl-color-gray-3, #888);
+    font-weight: normal;
+  }
+
+  .ts-config, .ts-storage {
+    border: 1px solid var(--sl-color-gray-5, #ccc);
+    border-radius: 6px;
+    padding: 0.6rem 0.8rem;
+    background: var(--sl-color-bg-nav, #fafafa);
+  }
+  .ts-config[open] summary, .ts-storage[open] summary {
+    margin-bottom: 0.5rem;
+  }
+  .ts-config summary, .ts-storage summary {
+    cursor: pointer;
+    font-size: 1rem;
+    padding: 0.2rem 0;
+  }
+  .ts-config-grid {
+    display: flex;
+    flex-direction: column;
+    gap: 0.7rem;
+  }
+  .ts-field {
+    display: flex;
+    flex-direction: column;
+    gap: 0.3rem;
+  }
+  .ts-field > span:first-child,
+  .ts-field > legend {
+    font-size: 0.9rem;
+    font-weight: 600;
+  }
+
+  .ts-categories {
+    border: 1px solid var(--sl-color-gray-6, #ddd);
+    border-radius: 4px;
+    padding: 0.5rem 0.7rem;
+    display: grid;
+    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
+    gap: 0.3rem 1rem;
+    align-items: center;
+  }
+  .ts-categories legend {
+    padding: 0 0.4rem;
+  }
+  .ts-categories label {
+    display: inline-flex;
+    align-items: center;
+    gap: 0.4rem;
+    font-size: 0.9rem;
+    font-family: var(--sl-font-system-mono, monospace);
+  }
+  .ts-categories .ts-hint {
+    grid-column: 1 / -1;
+  }
+
+  .ts-playground textarea, .ts-playground input[type="text"], .ts-playground select {
+    width: 100%;
+    font-family: var(--sl-font-system-mono, monospace);
+    font-size: 0.9rem;
+    padding: 0.5rem;
+    border: 1px solid var(--sl-color-gray-5, #ccc);
+    border-radius: 4px;
+    background: var(--sl-color-bg, white);
+    color: var(--sl-color-text, black);
+    box-sizing: border-box;
+  }
+  .ts-playground textarea {
+    font-size: 0.95rem;
+    padding: 0.6rem;
+    resize: vertical;
+  }
+  .ts-playground button {
+    padding: 0.4rem 0.9rem;
+    border-radius: 4px;
+    border: 1px solid var(--sl-color-gray-5, #ccc);
+    background: var(--sl-color-accent, #6b46c1);
+    color: white;
+    cursor: pointer;
+    font-weight: 500;
+    line-height: 1.4;
+    height: 2.2rem;
+    display: inline-flex;
+    align-items: center;
+  }
+  .ts-playground button.ts-danger {
+    background: #c0392b;
+    border-color: #a13225;
+  }
+  .ts-playground button:disabled { opacity: 0.5; cursor: progress; }
+  .ts-status {
+    font-family: var(--sl-font-system-mono, monospace);
+    font-size: 0.85rem;
+    color: var(--sl-color-gray-3, #888);
+    height: 2.2rem;
+    display: inline-flex;
+    align-items: center;
+  }
+  .ts-output {
+    padding: 0.7rem;
+    border: 1px solid var(--sl-color-gray-5, #ccc);
+    border-radius: 4px;
+    background: var(--sl-color-bg-nav, #fafafa);
+    color: var(--sl-color-text, black);
+    font-family: var(--sl-font, system-ui);
+    line-height: 1.55;
+    min-height: 4rem;
+    white-space: pre-wrap;
+    word-wrap: break-word;
+  }
+  .ts-output mark.ts-span {
+    background: rgba(255, 200, 0, 0.35);
+    color: inherit;
+    padding: 0 2px;
+    border-radius: 2px;
+    font-weight: 600;
+    border-bottom: 2px solid rgba(255, 200, 0, 0.8);
+  }
+  .ts-output mark.ts-span.ts-marker {
+    font-family: var(--sl-font-system-mono, monospace);
+    font-size: 0.9em;
+    border: 1px dashed currentColor;
+    border-bottom-width: 1px;
+    border-radius: 3px;
+    padding: 0 4px;
+    opacity: 0.95;
+  }
+  .ts-output mark.ts-span[data-label*="email"]   { background: rgba(120, 200, 255, 0.4); border-color: #4aa3df; }
+  .ts-output mark.ts-span[data-label*="phone"]   { background: rgba(180, 255, 180, 0.4); border-color: #5fbf5f; }
+  .ts-output mark.ts-span[data-label*="ssn"]     { background: rgba(255, 130, 130, 0.4); border-color: #e25555; }
+  .ts-output mark.ts-span[data-label*="name"]    { background: rgba(255, 200, 100, 0.4); border-color: #d49b3a; }
+  .ts-output mark.ts-span[data-label*="person"]  { background: rgba(255, 200, 100, 0.4); border-color: #d49b3a; }
+  .ts-output mark.ts-span[data-label*="address"] { background: rgba(220, 180, 255, 0.4); border-color: #a878d4; }
+  .ts-output mark.ts-span[data-label*="url"]     { background: rgba(180, 220, 255, 0.4); border-color: #4a8ad0; }
+  .ts-output mark.ts-span[data-label*="date"]    { background: rgba(255, 220, 180, 0.4); border-color: #d4823a; }
+  .ts-output mark.ts-span[data-label*="account"] { background: rgba(220, 220, 255, 0.4); border-color: #6b6bc5; }
+  .ts-output mark.ts-span[data-label*="secret"]  { background: rgba(255, 200, 200, 0.5); border-color: #d04444; }
+
+  .ts-spans, .ts-code {
+    font-size: 0.85rem;
+    background: var(--sl-color-bg-nav, #f5f5f5);
+    color: var(--sl-color-text, black);
+    padding: 0.5rem 0.7rem;
+    border-radius: 4px;
+    max-height: 320px;
+    overflow: auto;
+    white-space: pre-wrap;
+  }
+
+  .ts-storage-body {
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+  }
+  .ts-storage-info {
+    font-family: var(--sl-font-system-mono, monospace);
+    font-size: 0.85rem;
+    background: var(--sl-color-bg, white);
+    color: var(--sl-color-text, black);
+    border: 1px solid var(--sl-color-gray-6, #ddd);
+    border-radius: 4px;
+    padding: 0.5rem 0.7rem;
+  }
+  .ts-storage-info table { border-collapse: collapse; width: 100%; }
+  .ts-storage-info th, .ts-storage-info td { text-align: left; padding: 0.15rem 0.5rem; }
+  .ts-storage-info th { color: var(--sl-color-gray-3, #888); font-weight: 600; font-size: 0.8rem; }
+  .ts-storage-info .ts-total { font-weight: 600; }
+</style>
+
+<script>
+  // Educational note: import from "textsift-core" (the lean ~76KB
+  // gzipped package). The umbrella "textsift" works the same way and
+  // adds an auto fallback to transformers.js — useful for apps that
+  // need the auto path; not needed here because we always pick a
+  // backend explicitly.
+  import { PrivacyFilter, getCachedModelInfo, clearCachedModel } from "textsift-core";
+
+  const ALL_CATEGORIES = [
+    "private_person", "private_email", "private_phone", "private_address",
+    "private_url", "private_date", "account_number", "secret",
+  ];
+
+  const $input  = document.getElementById("ts-input");
+  const $run    = document.getElementById("ts-run");
+  const $redact = document.getElementById("ts-redact");
+  const $status = document.getElementById("ts-status");
+  const $output = document.getElementById("ts-output");
+  const $spans  = document.getElementById("ts-spans");
+  const $code   = document.getElementById("ts-code");
+
+  const $backend = document.getElementById("ts-backend");
+  const $modelSrc = document.getElementById("ts-model-source");
+  const $markers = document.getElementById("ts-markers");
+  const $reload = document.getElementById("ts-reload");
+  const $configHint = document.getElementById("ts-config-hint");
+
+  const $refreshStorage = document.getElementById("ts-refresh-storage");
+  const $wipe = document.getElementById("ts-wipe");
+  const $storageStatus = document.getElementById("ts-storage-status");
+  const $storageInfo = document.getElementById("ts-storage-info");
+
+  let filterPromise = null;
+  let currentFilter = null;
+
+  // The library's default modelSource. The input field is pre-filled
+  // with this so users can see the expected shape; we only pass it
+  // through to PrivacyFilter when it differs from the default (the
+  // library uses the same default internally).
+  const DEFAULT_MODEL_SOURCE = "https://huggingface.co/openai/privacy-filter";
+
+  function readConfig() {
+    const backend = $backend.value;
+    const sourceRaw = $modelSrc.value.trim();
+    const modelSource = (sourceRaw && sourceRaw !== DEFAULT_MODEL_SOURCE) ? sourceRaw : undefined;
+    const enabledCategories = ALL_CATEGORIES.filter(
+      (c) => document.querySelector(`input[type="checkbox"][data-cat="${c}"]`).checked,
+    );
+    let markers;
+    const raw = $markers.value.trim();
+    if (raw) {
+      try { markers = JSON.parse(raw); }
+      catch (err) { throw new Error("Invalid markers JSON: " + err.message); }
+    }
+    const opts = { backend };
+    if (modelSource) opts.modelSource = modelSource;
+    // enabledCategories goes to the per-call detect/redact options;
+    // markers can be set on either create() or per-call. Keep them
+    // per-call here so toggling a checkbox doesn't force a model
+    // reload.
+    return { createOpts: opts, callOpts: { enabledCategories, markers } };
+  }
+
+  function buildCodeSnippet(createOpts, callOpts, mode) {
+    const { backend, modelSource } = createOpts;
+    const createPretty = JSON.stringify(
+      { backend, ...(modelSource ? { modelSource } : {}) },
+      null, 2,
+    );
+    const callPretty = JSON.stringify(
+      Object.fromEntries(
+        Object.entries(callOpts).filter(
+          ([, v]) => v !== undefined && !(Array.isArray(v) && v.length === ALL_CATEGORIES.length),
+        ),
+      ),
+      null, 2,
+    );
+    const callArgs = callPretty === "{}" ? "input" : `input, ${callPretty}`;
+    return [
+      'import { PrivacyFilter } from "textsift";',
+      "",
+      `const filter = await PrivacyFilter.create(${createPretty});`,
+      `const result = await filter.${mode}(${callArgs});`,
+      "filter.dispose();",
+    ].join("\n");
+  }
+
+  function setStatus(msg) { $status.textContent = msg; }
+  function setStorageStatus(msg) { $storageStatus.textContent = msg; }
+
+  function escape(s) {
+    return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
+  }
+
+  function renderSpans(text, spans) {
+    if (!spans.length) return escape(text);
+    const sorted = [...spans].sort((a, b) => a.start - b.start);
+    let html = "", cursor = 0;
+    for (const s of sorted) {
+      html += escape(text.slice(cursor, s.start));
+      html += `<mark class="ts-span" data-label="${escape(s.label)}" title="${escape(s.label)}">${escape(text.slice(s.start, s.end))}</mark>`;
+      cursor = s.end;
+    }
+    html += escape(text.slice(cursor));
+    return html;
+  }
+
+  function renderRedacted(text, spans) {
+    if (!spans.length) return escape(text);
+    const sorted = [...spans].sort((a, b) => a.start - b.start);
+    let html = "", cursor = 0;
+    for (const s of sorted) {
+      const marker = s.marker ?? `[${s.label}]`;
+      html += escape(text.slice(cursor, s.start));
+      html += `<mark class="ts-span ts-marker" data-label="${escape(s.label)}" title="${escape(s.label)} (was: ${escape(s.text)})">${escape(marker)}</mark>`;
+      cursor = s.end;
+    }
+    html += escape(text.slice(cursor));
+    return html;
+  }
+
+  async function getFilter(createOpts) {
+    if (filterPromise) return filterPromise;
+    setStatus("loading model (first run downloads ~770 MB; cached after)…");
+    filterPromise = PrivacyFilter.create(createOpts)
+      .then((f) => { currentFilter = f; setStatus("model ready"); return f; })
+      .catch((err) => { filterPromise = null; setStatus("load failed: " + err.message); throw err; });
+    return filterPromise;
+  }
+
+  async function disposeFilter() {
+    if (currentFilter) {
+      try { currentFilter.dispose(); } catch {}
+      currentFilter = null;
+    }
+    filterPromise = null;
+  }
+
+  async function withButtonsDisabled(fn) {
+    $run.disabled = true; $redact.disabled = true; $reload.disabled = true; $wipe.disabled = true;
+    try { return await fn(); }
+    finally { $run.disabled = false; $redact.disabled = false; $reload.disabled = false; $wipe.disabled = false; }
+  }
+
+  $reload.addEventListener("click", () => withButtonsDisabled(async () => {
+    let cfg;
+    try { cfg = readConfig(); }
+    catch (err) { $configHint.textContent = err.message; return; }
+    $configHint.textContent = "";
+    setStatus("reloading…");
+    await disposeFilter();
+    await getFilter(cfg.createOpts);
+  }));
+
+  $run.addEventListener("click", () => withButtonsDisabled(async () => {
+    let cfg;
+    try { cfg = readConfig(); }
+    catch (err) { setStatus(err.message); return; }
+    const text = $input.value;
+    const filter = await getFilter(cfg.createOpts);
+    setStatus("detecting…");
+    const result = await filter.detect(text, cfg.callOpts);
+    $output.innerHTML = renderSpans(text, result.spans);
+    $spans.textContent = JSON.stringify(result, null, 2);
+    $code.textContent = buildCodeSnippet(cfg.createOpts, cfg.callOpts, "detect");
+    setStatus(`${result.spans.length} span(s) detected`);
+  }));
+
+  $redact.addEventListener("click", () => withButtonsDisabled(async () => {
+    let cfg;
+    try { cfg = readConfig(); }
+    catch (err) { setStatus(err.message); return; }
+    const text = $input.value;
+    const filter = await getFilter(cfg.createOpts);
+    setStatus("redacting…");
+    const result = await filter.redact(text, cfg.callOpts);
+    $output.innerHTML = renderRedacted(text, result.spans);
+    $spans.textContent = JSON.stringify(result, null, 2);
+    $code.textContent = buildCodeSnippet(cfg.createOpts, cfg.callOpts, "redact");
+    setStatus(`${result.spans.length} span(s) replaced`);
+  }));
+
+  // ── Storage panel ───────────────────────────────────────
+
+  function fmtBytes(n) {
+    if (n < 1024) return `${n} B`;
+    if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
+    if (n < 1024 * 1024 * 1024) return `${(n / 1024 / 1024).toFixed(1)} MB`;
+    return `${(n / 1024 / 1024 / 1024).toFixed(2)} GB`;
+  }
+
+  async function refreshStorage() {
+    setStorageStatus("checking…");
+    try {
+      const info = await getCachedModelInfo();
+      if (!info.supported) {
