+        setStorageStatus("0 bytes");
+        return;
+      }
+      const rows = info.entries
+        .sort((a, b) => b.bytes - a.bytes)
+        .map((e) => `<tr><td>${escape(e.name)}</td><td>${fmtBytes(e.bytes)}</td></tr>`)
+        .join("");
